var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"인원이 다 모인 것 같으니 이제부터 작전을 설명하지.","JPN":"全員揃ったみたいだから、これから作戦の説明をする。","ENG":"Since it seems everyone's here, I'll fill you in on the operation.","TWN":"大家都到齊了，那現在開始說明作戰規劃吧。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"작전의 목표는 두 가지다.","JPN":"作戦の目標は二つ。","ENG":"We have two objectives.","TWN":"本次作戰的目標有兩個。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"첫째는 차원의 틈에 숨어 있는 리플레이서 기함, 뉴 오하이오의 좌표를 찾아내는 것.","JPN":"一つ目は次元の狭間に隠れているリプレイサー総旗艦、ニューオハイオの座標を見つけること。","ENG":"First, we find the coordinates of the New Ohio, flagship of the Replacer Syndicate, now hiding between dimensions.","TWN":"第一，找出隱藏在次元縫隙裡的克隆集團旗艦，新俄亥俄的座標。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그리고 두 번째는 뉴 오하이오의 차원도약 기능을 마비시키고 관리국 태스크포스들을 불러 리플레이서를 격멸하는 것.","JPN":"そして二つ目は、ニューオハイオの次元跳躍機能を麻痺させた後、\\n管理局のタスクフォースを呼び出してリプレイサーを撃滅させること。","ENG":"Second, we cripple the New Ohio's dimension jump system, call the Administration TASKFORCEs, and eliminate the Replacer forces.","TWN":"接著第二，癱瘓新俄亥俄的次元躍遷功能，並召集管理局的特遣勢力，擊敗克隆集團。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......좋아, 그런데 놈들을 어떻게 찾지?","JPN":"……了解、だけど、どうやって奴らを見つけるの？","ENG":"Fine. But how are you going to find them?","TWN":"……很好。但我們要怎麼找到那些傢伙呢？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"간단해.","JPN":"簡単だ。","ENG":"It's simple.","TWN":"很簡單。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이동형이건 아니건 불멸체 코어는 단말과 어떤 식으로든 연결되어 있어야 한다.","JPN":"移動型かどうかにかかわらず、不滅体コアは何らかの方法で端末と繋がってなければならない。","ENG":"Mobile or stationary, the Immortal System Core must stay connected to the terminals.","TWN":"無論是不是可移動型，不滅者核心都得以某種形式和終端連接著。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래야 부서진 로스트 쉽을 복구할 수가 있으니까.","JPN":"そうしてこそ、壊れたロストシップを復旧することができるんだ。","ENG":"Or it would be impossible for them to restore the destroyed Lost Ships.","TWN":"因為只有這樣，才能修補好被破壞的失落艦船。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이 연결은 차원간섭파를 통해 이루어지기 때문에 일반적으로는 추적이 불가능해.","JPN":"その繫がりは次元干渉波を介しているから、通常は追跡できないんだ。","ENG":"And this connection is made through dimension interference waves, which makes it impossible to trace.","TWN":"而這個連接是通過次元干涉波進行的，所以一般來說，是不可能追蹤到的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하지만...... 사실 뉴 오하이오의 통신 출력만으로는 불멸체 코어와 전 세계의 로스트 쉽 간의 데이터 링크를 유지할 수 없어.","JPN":"だが……実は、ニューオハイオの通信出力だけじゃ、\\n不滅体コアと世界中のロストシップとのデータリンクが維持できないのが現状だ。","ENG":"However, the output of the communication device equipped on the New Ohio isn't enough to maintain the data link between the Immortal System Core and all the Lost Ships around the world.","TWN":"但是……實際上，光靠新俄亥俄的通信輸出，是無法維持不滅者核心和全世界失落艦船之間的數據連結的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래서 불멸체 코어의 차원간섭파를 전 세계로 송출해 주는 허브가 존재한다.","JPN":"そのため、不滅体コアの次元干渉波を世界中に発信するハブが存在するんだよ。","ENG":"This is the reason they're using hubs that transmit the dimension interference waves of the Immortal System Core to the entire world.","TWN":"所以，應該還存在著向全世界傳送不滅者核心次元干涉波的集線器。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"허브?","JPN":"ハブ？","ENG":"Hubs?","TWN":"集線器？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래, 휴대폰 기지국이라고 하면 이해하기 쉽겠지.","JPN":"そうだ、携帯基地局というとしっくりくるかもな。","ENG":"Think of them as cell towers of telecommunication companies.","TWN":"對，妳就想成是手機的基地台，這樣就很容易理解了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"우리가 찾아야 할 건 바로 이 녀석들이다.","JPN":"俺らが探すのは、まさにそいつらだ。","ENG":"And these hubs are what we're after.","TWN":"我們要找的，正是這個東西。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"리플레이서가 만들어 낸 차원간섭파 증폭용 자율방어 융합체.","JPN":"リプレイサーが作り出した、次元干渉波増幅用の自律防御融合体。","ENG":"The Replacers' autonomous defense hybrider created to amplify dimension interference waves,","TWN":"克隆集團製造出的次元干涉波增幅用自動防禦融合體。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"통칭, 어보미네이션.","JPN":"通称、アボミネーション。","ENG":"otherwise known as Abominations.","TWN":"通稱，憎惡。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"뭐...... 뭐야, 저게?","JPN":"な……なんだ、あれ？","ENG":"W-what's that thing?","TWN":"那……那是什麼鬼啊？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABOMINATION_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"끔찍하게 생겼네...... 취향 나쁘군.","JPN":"うわ……趣味悪い。","ENG":"It looks horrendous. Yuk.","TWN":"長得真嚇人呢……真是奇怪的嗜好啊。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABOMINATION_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이 어보미네이션들은 뉴 오하이오와는 달리 이면세계의 특정 좌표에 고정되어 있다.","JPN":"このアボミネーションは、ニューオハイオとは違って裏世界の特定座標に固定されている。","ENG":"Unlike the New Ohio, these Abominations stay put in fixed positions in the Counterside.","TWN":"與新俄亥俄不同，這個憎惡們固定在異界的特定座標上。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"거기서 불멸체 코어와 로스트 쉽의 연결을 유지하는 거지.","JPN":"そこで不滅体コアとロストシップの繫がりを維持してるんだ。","ENG":"They're stationed there to keep the Immortal System Core and the Lost Ships connected.","TWN":"並在那裡維持不滅者核心和失落艦船的連接。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"고정위치라...... 그런 건가요?","JPN":"固定位置……そういうことですか。","ENG":"Fixed coordinates, huh? I see.","TWN":"固定位置……是這樣嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"눈치챘나 보군.","JPN":"気づいたようだな。","ENG":"So you've caught on?","TWN":"看來你已經察覺到了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"불멸체 코어가 이동 가능한 건......","JPN":"不滅体コアが移動できるのは……","ENG":"The Immortal System Core can be moved around","TWN":"不滅者核心之所以可以移動……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그 어보미네이션이라는 기지국들이 코어 대신 고정 좌표에 박혀 있기 때문이겠죠.","JPN":"そのアボミネーションという基地局が、コアの代わりに固定座標に埋め込まれているからでしょうね。","ENG":"because the cell towers called the Abominations are placed on certain locations instead of it.","TWN":"就是因為這個被稱為憎惡的基地台，它代替了核心埋在了固定座標上吧。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......정확해.","JPN":"……そのとおりだ。","ENG":"Precisely.","TWN":"……沒錯。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그리고 이 어보미네이션들을 파괴한 후 해당 위치에서 대량의 차원폭풍을 일으키면,","JPN":"このアボミネーションを破壊した後、その位置で大量の次元暴風を起こせば、","ENG":"And by destroying these Abominations and causing a chain of dimension storms,","TWN":"然後破壞這個憎惡後，那個地方就會產生大量的次元風暴……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"불멸체 코어가 송신하는 차원간섭파를 외부에서 관측할 수 있게 된다.","JPN":"不滅体コアが発信する次元干渉波を外部から観測できるようになる。","ENG":"we become able to observe the dimension interference waves transmitted from the Immortal System Core,","TWN":"不滅者核心發送的次元干涉波就可以從外界觀測到了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그럼 그 정보를 역추적해서 코어의 위치도 알아낼 수 있지.","JPN":"その情報を逆追跡すれば、コアの位置も調べることができるんだ。","ENG":"and reverse calculate the location of the Core itself.","TWN":"這樣一來，我們就能透過反向追蹤，掌握核心所在的位置了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"과연...... 그런 방법이 있었군요.","JPN":"なるほど……そんな方法があったんですね。","ENG":"I see. It actually sounds like a viable plan.","TWN":"原來……有這樣的方法啊！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그럼 뭘 망설이는 거죠?","JPN":"なら、何を躊躇ってるんですか？","ENG":"Then what are we waiting for?","TWN":"那我們還在猶豫什麼？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"당장 놈들을 해치우러 출동해야 합니다.","JPN":"今すぐ奴らの討伐にいかなければ。","ENG":"Let's head out and finish them off.","TWN":"立刻出動，準備除掉那些傢伙吧！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"말처럼 간단한 일이 아니야.","JPN":"言うほど簡単じゃないからだよ。","ENG":"There's a problem.","TWN":"這件事沒有跟說得一樣簡單。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"어보미네이션은 총 4개체다.","JPN":"アボミネーションは全部で4つだ。","ENG":"There are four Abominations in total.","TWN":"憎惡一共分為4個部分。"},"stage":{"bg":"MAINSTREAM_5201001","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"내가 너희들을 모두 모은 건, 이 4개체를 동시에 파괴해야 하기 때문이야.","JPN":"俺があんたらを集結させたのは、この4つの個体を同時に破壊する必要があるからなんだよ。","ENG":"And the reason I've assembled all of you is that all four must be destroyed simultaneously.","TWN":"我把你們都召集起來，就是為了要同時破壞這四個部分。"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"동시에......?","JPN":"同時に……？","ENG":"Simultaneously?","TWN":"同時……？"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래. 만약 어보미네이션들을 순차적으로 파괴한다면 놈들이 이상을 눈치채고 대응방안을 강구할지도 몰라.","JPN":"そうだ、アボミネーションを順次破壊すると、\\n奴らが途中で異常を察知して何か対策を講ずるかもしれない。","ENG":"You heard me. If the Abominations go down one by one, the Replacers will catch on and come up with a countermeasure.","TWN":"對，如果我們逐一破壞它們，那些傢伙有可能會覺察到異常，並擬定對應的策略。"},"stage":{"bg":"MAINSTREAM_5201003","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그런 위험을 피하려면 놈들이 우리의 공격을 눈치채기 전,","JPN":"そのリスクを回避するためには、奴らが俺らの攻撃に気づく前に、","ENG":"To minimize the risk of them finding out they're under attack,","TWN":"為了回避這個風險，我們得在敵人察覺我們的攻擊之前……"},"stage":{"bg":"MAINSTREAM_5201003","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"일거에 모든 어보미네이션을 파괴하고 뉴 오하이오가 숨어있는 좌표로 돌입해야 한다.","JPN":"全てのアボミネーションを一挙に破壊して、\\nニューオハイオが隠れている座標に突入しなければならないんだ。","ENG":"we must destroy all four Abominations at the same time and get to the coordinates where the New Ohio is hiding as fast as we can.","TWN":"一口氣破壞所有的憎惡，然後殺進新俄亥俄隱藏的座標。"},"stage":{"bg":"MAINSTREAM_5201003","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어...... 질문이 있는데요.","JPN":"うーん、一つ質問ですが、","ENG":"Umm... I have a question.","TWN":"呃……我有個問題。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"작전대로 됐다고 치고, 뉴 오하이오는 어떻게 멈추실 거죠?","JPN":"作戦どおりに進んだとして、ニューオハイオはどうやって止めるつもりです？","ENG":"Let's say everything worked out as planned. How are you going to stop the New Ohio?","TWN":"如果作戰發展就跟預期的一樣，那到時候我們要怎麼阻止新俄亥俄？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"상대는 관리국 연합함대 3척을 한 순간에 격침시켜 버릴 정도의 화력을 가지고 있어요.","JPN":"相手は管理局連合艦隊の3艦を一瞬にして撃沈させるほどの火力を保持しています。","ENG":"The ship has massive firepower, enough to wipe 3 out Administration multinational coalition fleet vessels in the blink of an eye.","TWN":"對方可是擁有瞬間將管理局的三艘聯合艦隊擊沉的火力。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"우리 전력으로는 계란으로 바위치기일 텐데요?","JPN":"私たちの戦力じゃ到底歯が立たないのでは？","ENG":"Don't you think we'd look like a flea against an elephant?","TWN":"以我們的戰力無異於是以卵擊石吧？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"정면으로 싸울 필요는 없지.","JPN":"真っ向勝負する必要はないんだ。","ENG":"We won't have to fight them head on.","TWN":"我們沒有必要和他們正面交鋒。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이전에 말했듯이, 리플레이서 메인 컴퓨터에는 형이 심어놓은 백도어 코드가 있다.","JPN":"以前も話したように、兄貴はリプレイサーのメインコンピューターに、バックドアコードを埋め込んでおいたんだ。","ENG":"Like I said before, my brother planted a backdoor in the Replacers' main computer.","TWN":"正如我之前所說，在克隆集團的電腦主機裡，有我哥植入的後門代碼。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"데이터 링크가 가능한 지점까지만 가면 관리자 명령어를 통해 즉시 함선의 차원도약과 스텔스 기능을 정지시킬 수 있어.","JPN":"データリンクが可能な地点にたどり着けさえすれば、\\nコマンドを使ってただちに艦船の次元跳躍やステルス機能を止めることができる。","ENG":"We can disable the New Ohio's dimension jump and stealth system with the administrator command if we get close enough for a data link.","TWN":"我們只要到達能連接數據的地方，然後使用管理員指令，就能立刻停止艦船的次元躍遷和隱形功能。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"우리 역할은 거기까지다.","JPN":"俺らの役目はそこまでだ。","ENG":"That's where our role ends.","TWN":"我們的任務就到此為止了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그 이후에는 관리국에 연락해서 태스크포스 함대를 불러오기만 하면 돼.","JPN":"そのあとは管理局に連絡して、タスクフォース艦隊を呼んでくればいいんだ。","ENG":"All we need to do next is contact the Administration and call for the TASKFORCE fleet.","TWN":"之後只要聯絡管理局，把特遣勢力的艦隊叫過來就行了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"간단하지?","JPN":"簡単だろ？","ENG":"It's simple as that.","TWN":"很簡單吧？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하...... 계획은 간단하네요.","JPN":"はは……たしかに計画は簡単ですね。","ENG":"Hah hah... It sounds simple.","TWN":"哈哈……計畫是很簡單啦。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"계획은 말이죠......","JPN":"計画は、ですが……","ENG":"But I don't know if carrying it out would be as simple as it sounds...","TWN":"計畫……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"그런데 거긴 대체 어떻게 간다는 거야?","JPN":"だけど、いったいどうやってそこまでたどり着くってんだ？","ENG":"But how the heck are we going to get there?","TWN":"但我們到底要怎麼去那裡啊？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"어보미네이션이란 놈들은 이면세계에 있다면서?","JPN":"アボミネーションって連中は裏世界にいるんだろ？","ENG":"Aren't the Abominations in the Counterside?","TWN":"憎惡那東西是在異界裡吧？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"맞아.","JPN":"そう。","ENG":"She's right.","TWN":"是啊。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"아직 내 질문에는 답을 못 들었어.","JPN":"まだ私の質問の答えを聞いてない。","ENG":"You haven't answered my question yet.","TWN":"我的疑問還沒有獲得解答。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"차원함도 없는데 어떻게 이면세계로 다이브 할 생각이지?","JPN":"次元艦もないのに、どうやって裏世界にダイブするの？","ENG":"How are we going to do a dive without a dimension ship?","TWN":"我們連次元艦都沒有，要怎樣才能躍入異界呢？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"그건...... 아주 멋진 걸 준비해 뒀지.","JPN":"それはな……すごくクールな奴を用意しといたんだ。","ENG":"Ah, about that. I came up with a wonderful idea.","TWN":"這個啊……因為我們準備了一個非常酷的東西。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"보고 놀라지나 말라고.","JPN":"見て驚くなよ。","ENG":"Be prepared to be surprised.","TWN":"你們看了不要太驚訝喔。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"이, 이건......?","JPN":"こ、これは……？","ENG":"H-huh?","TWN":"這、這是……？"},"stage":{"bg":"MAINSTREAM_5201010","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"뭐야? 이 깡통 같은 건!","JPN":"なんだ、このボロ缶は！","ENG":"What is this? This looks like a giant tin can!","TWN":"這什麼？像罐頭一樣的東西！"},"stage":{"bg":"MAINSTREAM_5201010","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"깡통이라니.","JPN":"ボロ缶だなんて、ひどいな。","ENG":"Tin can?","TWN":"竟然說是罐頭。"},"stage":{"bg":"MAINSTREAM_5201010","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"하여간 요즘 친구들은 이 물건의 진가를 몰라보는군.","JPN":"これだから最近の若者は。本物を知らないんだな。","ENG":"You later generations just don't appreciate the real worth of this beauty.","TWN":"算了，現在的小孩都不知道這件東西的真正價值。"},"stage":{"bg":"MAINSTREAM_5201010","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"이건 <color=#ffd34c>강하선</color>이라는 걸세.","JPN":"これは<color=#ffd34c>降下船</color>というものだ。","ENG":"This is called the <color=#ffd34c>Drop Ship</color>.","TWN":"這叫作<color=#ffd34c>降落艙</color>。"},"stage":{"bg":"MAINSTREAM_5201010","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"소유즈 우주선의 귀환 캡슐을 개조해서 이면세계로 다이브 할 수 있게 만든 거지.","JPN":"ソユーズ宇宙船の帰還カプセルを改造して、裏世界にダイブできるようにしてあるんだ。","ENG":"It was built from the Soyuz space capsule specifically for diving.","TWN":"這是把聯盟號太空船的返回艙進行了改造，使其能夠躍入到異界。"},"stage":{"bg":"MAINSTREAM_5201010","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"이걸 타고 가면 될 거다.","JPN":"これに乗っていくと良いだろう。","ENG":"This is what you're going to be traveling in.","TWN":"我們坐這個去就可以了。"},"stage":{"bg":"MAINSTREAM_5201010","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......뭐? 이걸?","JPN":"……え？　これに？","ENG":"Huh? This thing?","TWN":"……什麼？就這個？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"호오...... 재미있네요.","JPN":"ほほう……面白いですね。","ENG":"Hmm... It's looks interesting.","TWN":"哦……真是有趣呢。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"이 골동품을 타고 이면세계로 떨어지라고?","JPN":"こんな骨董品に乗って裏世界に行けだと？","ENG":"You're throwing us away to the Counterside in this old thing?","TWN":"你要我們搭這個古董到異界去？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"지금 제정신이야?!","JPN":"気は確かか！？","ENG":"Are you out of your mind?","TWN":"你是認真的嘛？！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"너희들 세대는 잘 모르겠지만......","JPN":"君らの世代はよく知らないだろうが……","ENG":"I don’t know about your generation,","TWN":"雖然你們這一代不太清楚……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"이면세계 탐사 초기에는 다들 이런 걸 썼다고.","JPN":"裏世界探査が始まった頃にはみんなこういうのに乗ってたんだ。","ENG":"but this is what we used back in the early days of Counterside exploration.","TWN":"但在異界探索的初期，大家都是用這個東西的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"그리고 이래 봬도 안정성은 높은 편이다.","JPN":"こう見えても安定性は高いほうでな、","ENG":"As plain as it may look, it's a safe mode of transportation.","TWN":"而且別看它這樣，它的穩定性是很高的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"통계적으로도 사고율은...... 3% 미만이지.","JPN":"統計から見ても、事故率は……3％未満だ。","ENG":"Statistically speaking, its accident rate has never been over 3%.","TWN":"從統計資料上來看，事故發生率……還不到3%。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"100명 중에 3명은 죽는다는 소리잖아!","JPN":"それって100人のうち、3人は死ぬってこったろ！","ENG":"That's three out of a hundred!","TWN":"也就是說100人中會有3人死掉嘛！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"뭐가 안정적이라는 거야?!!","JPN":"何が安定的だ！？","ENG":"How can anyone call that safe?","TWN":"哪來什麼穩定？！！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"그런데 이거......","JPN":"ところで、これ……","ENG":"By the way...","TWN":"但是這個……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"강하는 그렇다 치고 귀환은 어떻게 하는 거지?","JPN":"降下はできるとしても、帰還はどうやって……？","ENG":"how are we going to come back after we do the dive in this?","TWN":"躍入就算了，我們要怎麼回來呢？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"......강하선이라고 했잖나.","JPN":"……降下船と言っただろ。","ENG":"I told you, it's a \\"drop\\" ship.","TWN":"……我一直說它叫降落艙啊。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"상위 차원으로 부상하는 기능은 없어.","JPN":"上位の次元に浮上する機能はないんだ。","ENG":"It drops things off, but it can't surface to the upper dimension.","TWN":"它沒有躍出上位次元的功能。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"......걱정 말게나.","JPN":"……心配するな。","ENG":"But don't worry.","TWN":"不用擔心啦。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"계획이 성공하면 관리국에서 보낸 구조선을 통해서 돌아올 수 있을 테니까.","JPN":"計画が成功すれば、管理局からの救助船で帰還できるはずだ。","ENG":"If the plan works out, you'll be able to return on the Administration's rescue ship.","TWN":"如果計畫成功的話，我們可以搭管理局派來的救援船回去啊。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"손자병법에도 있지 않나?","JPN":"「孫子の兵法」にもあるじゃないか。","ENG":"I believe it's even in that book Art of War by Sun Tsu.","TWN":"孫子兵法裡，不是也有這樣的故事嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"필승을 위한 배수의 진이라는 거지.","JPN":"必勝のための背水の陣ってことさ。","ENG":"You're burning the bridges behind you before an all-out battle.","TWN":"為了必勝的背水一戰啊。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"......이건 미친 짓이야.","JPN":"……正気じゃない。","ENG":"This is madness!","TWN":"……這是瘋了吧。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그야말로 자살특공이로군.","JPN":"自殺特攻って、これのことね。","ENG":"We're literally a suicide squad.","TWN":"真是自殺特攻隊啊。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 요즘 공무원들도 이런 걸 작전이라고 제출하지는 않을 텐데......","JPN":"ははは、今時、公務員でもそんなずさんな作戦は立てないと思いますが……","ENG":"Hah hah, my colleagues working in the special forces would never submit a plan this reckless.","TWN":"哈哈，就算是最近的公務員們，也不會提出這樣的作戰吧。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그쪽 동네는 좀 다른가 봐요?","JPN":"そちらの業界はまた別なんですかね？","ENG":"I guess things are a bit different in your line of business.","TWN":"看來你那邊的風氣好像有點不一樣喔。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"칭찬 고맙군.","JPN":"褒め言葉をありがとう。","ENG":"I appreciate the compliment.","TWN":"謝謝誇獎。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래서 빠질 사람 있나?","JPN":"それで、抜けたい奴は？","ENG":"So, does anyone want out?","TWN":"所以有人要退出嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"좋아, 다들 의견이 하나로 모인 것 같아 기쁘군.","JPN":"よし、みんな一致団結してるようで嬉しいな。","ENG":"Good. I'll glad to see opinions agree.","TWN":"很好，很高興大家意見一致。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그럼 팀을 나누도록 하지.","JPN":"では、チームを分けるとしよう。","ENG":"Now, let's divide the teams.","TWN":"那麼我們就開始分組吧。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"알트 소대와 오르카의 팀이 각각 어보미네이션 하나씩.","JPN":"アルト小隊とオルカのチームが、アボミネーションをそれぞれ一つずつ、","ENG":"ALT Squad and Orca's team, take one Abomination each.","TWN":"阿爾特小隊和奧爾卡小隊，兩隊各自負責一個憎惡。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그리고 경찰 나리들과 프리라이더 친구들이 같이 한 마리를 잡는다.","JPN":"警察組とフリーダム・ライダーズが合同で一つ。","ENG":"The police ladies and Free Riders will take another one,","TWN":"然後警察大人們和自由騎士的朋友們，一起解決一個憎惡。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼 마지막 하나는......","JPN":"じゃあ、残り一つは……？","ENG":"and for the last one...","TWN":"那最後……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"펜릴 소대 친구들은 나와 함께 가도록 하지.","JPN":"フェンリル小隊は、俺と一緒に行こう。","ENG":"Fenrir Squad and I will take care of it.","TWN":"芬里爾小隊的朋友就和我一起去吧。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"......이봐, 동생.","JPN":"……ねえ、弟くん。","ENG":"Hello, little brother.","TWN":"……喂，弟弟。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"뭔가 빼먹은 것 같지 않아?","JPN":"何か忘れてないかしら？","ENG":"Haven't you forgotten someone?","TWN":"你是不是遺漏了什麼啊？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"후우...... 할 수 없군.","JPN":"はあ……しょうがないな。","ENG":"*Sigh* Fine.","TWN":"呼……真是拿你們沒辦法啊。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"기타 떨거지들도 나와 함께 간다.","JPN":"そこの雑魚どもも、俺らと一緒だ。","ENG":"I'm taking all the rest of the losers with me.","TWN":"那其他的小嘍嘍也一起去吧。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......이제 됐나?","JPN":"……これで満足か？","ENG":"Are you happy now?","TWN":"……這樣總行了吧？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"떨거지라는 말 후회하게 해 주지!","JPN":"雑魚どもって言ったこと、後悔させてやるぜ！","ENG":"I'm going to make you regret calling me a loser!","TWN":"居然說我們是小嘍嘍，我們會讓你後悔說了這句話的！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"드디어 우리의 실력을 보여줄 때가 왔군.","JPN":"ついに俺たちの実力を証明する時が来たな。","ENG":"It's time that you saw what we're capable of.","TWN":"能夠展現我們實力的時刻終於來了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"이봐, 정보부 형씨.","JPN":"おい、情報局のお偉いさんよ。","ENG":"Hey, intelligence guy.","TWN":"喂，情報部的老兄！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"전에 말한 국가예산급 의뢰비, 잊지 말라고!","JPN":"この前言ってた国家予算級の報酬のこと、忘れんなよ！","ENG":"Don't forget, you said the reward would be as big as a year's national budget.","TWN":"之前說過的國家預算級委託費，你可別忘了喔！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"......알았으니까 살아만 돌아오게.","JPN":"……わかったから、生きて帰ってくるんだ。","ENG":"I won't. Just make sure you come back alive.","TWN":"……我知道啦，所以你們一定要活著回來。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"이 정도 일을 독단으로 처리한 시점부터 이미 내 모가지도 간당간당하다고.","JPN":"今回のことを独断で決めた時点で、私もクビ寸前なんだ。","ENG":"I'm putting my career on the line by planning something this big at my own discretion.","TWN":"從我這麼專斷獨行的這一刻開始，我離被炒魷魚也不遠了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"임무만 완수한다면 까짓 뭐든 못해 주겠나?","JPN":"任務さえ完遂できたら、何だって聞くつもりさ。","ENG":"You get the job done, and I'll even pick the stars for you.","TWN":"只要能完成任務，有什麼不能做的？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그럼 시간낭비 하지 말고 바로 출발한다.","JPN":"さあ、時間がもったいない。すぐに出発しよう。","ENG":"Now, let's stop wasting time and get going.","TWN":"那就別浪費時間了，馬上出發吧。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"어보미네이션의 좌표는 각자 탑승할 강하선에 입력되어 있을 거야.","JPN":"アボミネーションの座標は、それぞれ搭乗する降下船に入力されてるはずだ。","ENG":"I've already set the coordinates of each Abomination in the drop ships you'll be diving in.","TWN":"憎惡的座標會輸入在各自搭乘的降落艙上。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"가서 저 빌어먹을 놈들의 엉덩이를 걷어차 주자고.","JPN":"着いたら、あのくそったれどものケツを蹴っ飛ばしてやろうぜ。","ENG":"Let's go kick those bastards in the butt.","TWN":"準備去踹那些混蛋的屁股一腳吧。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};